function solve(n, edges, label) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 0;

    // We'll use BFS with a state that tracks visited nodes and character counts
    // The state will be a bitmask for visited nodes and a frequency map for characters
    // Since n is small (<=14), bitmask is feasible

    for (let start = 0; start < n; start++) {
        const queue = [];
        const visitedMask = 1 << start;
        const charCount = new Array(26).fill(0);
        const charCode = label.charCodeAt(start) - 'a'.charCodeAt(0);
        charCount[charCode]++;
        queue.push({ node: start, mask: visitedMask, counts: [...charCount], length: 1 });

        while (queue.length > 0) {
            const { node, mask, counts, length } = queue.shift();

            // Check if current path can form a palindrome
            let oddCount = 0;
            for (let i = 0; i < 26; i++) {
                if (counts[i] % 2 !== 0) {
                    oddCount++;
                }
            }
            if (oddCount <= 1) {
                if (length > maxLen) {
                    maxLen = length;
                }
            }

            // Explore neighbors
            for (const neighbor of adj[node]) {
                if (!(mask & (1 << neighbor))) {
                    const newMask = mask | (1 << neighbor);
                    const newCounts = [...counts];
                    const neighborChar = label.charCodeAt(neighbor) - 'a'.charCodeAt(0);
                    newCounts[neighborChar]++;
                    queue.push({
                        node: neighbor,
                        mask: newMask,
                        counts: newCounts,
                        length: length + 1
                    });
                }
            }
        }
    }

    return maxLen;
}

